// pages/LoginPage.ts
import { Page, Locator } from '@playwright/test';

export class LoginPage {
  readonly usernameInput: Locator;
  readonly passwordInput: Locator;
  readonly loginButton: Locator;
  readonly errorMessage: Locator;

  constructor(private page: Page) {
    this.usernameInput = page.locator('#username');
    this.passwordInput = page.locator('#password');
    this.loginButton = page.getByRole('button', { name: 'Login' });
    this.errorMessage = page.locator('.error');
  }

  async navigate(): Promise<LoginPage> {
    await this.page.goto('https://practice.expandtesting.com/login');
    return this;
  }

  async login(username: string, password: string): Promise<LoginPage> {
    await this.usernameInput.fill(username);
    await this.passwordInput.fill(password);
    await this.loginButton.click();
    return this;
  }

  async getErrorMessage(): Promise<string | null> {
    return await this.errorMessage.textContent();
  }
}

// pages/DashboardPage.ts
import { Page, Locator } from '@playwright/test';

export class DashboardPage {
  readonly welcomeMessage: Locator;
  readonly logoutButton: Locator;

  constructor(private page: Page) {
    this.welcomeMessage = page.locator('.welcome');
    this.logoutButton = page.getByRole('button', { name: 'Logout' });
  }

  async isLoaded(): Promise<boolean> {
    await this.welcomeMessage.waitFor();
    return true;
  }

  async logout(): Promise<void> {
    await this.logoutButton.click();
  }
}

// tests/login.spec.ts
import { test, expect } from '@playwright/test';
import { LoginPage } from '../pages/LoginPage';
import { DashboardPage } from '../pages/DashboardPage';

test.describe('Login Tests', () => {
  test('successful login', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.navigate();
    await loginPage.login('practice', 'SuperSecretPassword!');

    const dashboard = new DashboardPage(page);
    await expect(dashboard.welcomeMessage).toBeVisible();
  });

  test('failed login', async ({ page }) => {
    const loginPage = new LoginPage(page);
    await loginPage.navigate();
    await loginPage.login('invalid', 'invalid');

    const error = await loginPage.getErrorMessage();
    expect(error).toContain('invalid');
  });
});
